import{_ as e,o as i,c as t,a2 as a}from"./chunks/framework.YhErEiPK.js";const c=JSON.parse('{"title":"How to Do Stubs Versioning?","description":"","frontmatter":{},"headers":[],"relativePath":"howto/stubs-versioning.md","filePath":"howto/stubs-versioning.md"}'),n={name:"howto/stubs-versioning.md"};function o(h,s,r,p,l,d){return i(),t("div",null,[...s[0]||(s[0]=[a('<h1 id="how-to-do-stubs-versioning" tabindex="-1">How to Do Stubs Versioning? <a class="header-anchor" href="#how-to-do-stubs-versioning" aria-label="Permalink to &quot;How to Do Stubs Versioning?&quot;">​</a></h1><p>This section covers versioning of the stubs, which you can handle in a number of different ways:</p><ul><li><a href="#api-versioning">API Versioning</a></li><li><a href="#jar-versioning">JAR Versioning</a></li><li><a href="#development-or-production-stubs">Development or Production Stubs</a></li></ul><h2 id="api-versioning" tabindex="-1">API Versioning <a class="header-anchor" href="#api-versioning" aria-label="Permalink to &quot;API Versioning&quot;">​</a></h2><p>What does versioning really mean? If you refer to the API version, there are different approaches:</p><ul><li>Use hypermedia links and do not version your API by any means</li><li>Pass the version through headers and URLs</li></ul><p>We do not try to answer the question of which approach is better. You should pick whatever suits your needs and lets you generate business value.</p><p>Assume that you do version your API. In that case, you should provide as many contracts with as many versions as you support. You can create a subfolder for every version or append it to the contract name — whatever suits you best.</p><h2 id="jar-versioning" tabindex="-1">JAR Versioning <a class="header-anchor" href="#jar-versioning" aria-label="Permalink to &quot;JAR Versioning&quot;">​</a></h2><p>If, by versioning, you mean the version of the JAR that contains the stubs, then there are essentially two main approaches.</p><p>Assume that you do continuous delivery and deployment, which means that you generate a new version of the jar each time you go through the pipeline and that the jar can go to production at any time. For example, your jar version looks like the following (because it got built on the 20.10.2016 at 20:15:21):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1.0.0.20161020-201521-RELEASE</span></span></code></pre></div><p>In that case, your generated stub jar should look like the following:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1.0.0.20161020-201521-RELEASE-stubs.jar</span></span></code></pre></div><p>In this case, you should, inside your <code>application.yml</code> or <code>@AutoConfigureStubRunner</code> when referencing stubs, provide the latest version of the stubs. You can do that by passing the <code>+</code> sign:</p><div class="language-java vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">@</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">AutoConfigureStubRunner</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ids</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;com.example:http-server-dsl:+:stubs:8080&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">})</span></span></code></pre></div><p>If the versioning, however, is fixed (for example, <code>1.0.4.RELEASE</code> or <code>2.1.1</code>), you have to set the concrete value of the jar version:</p><div class="language-java vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">@</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">AutoConfigureStubRunner</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ids</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;com.example:http-server-dsl:2.1.1:stubs:8080&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">})</span></span></code></pre></div><h2 id="development-or-production-stubs" tabindex="-1">Development or Production Stubs <a class="header-anchor" href="#development-or-production-stubs" aria-label="Permalink to &quot;Development or Production Stubs&quot;">​</a></h2><p>You can manipulate the classifier to run the tests against the current development version of the stubs of other services or the ones that were deployed to production. If you alter your build to deploy the stubs with the <code>prod-stubs</code> classifier once you reach production deployment, you can run tests in one case with development stubs and in another case with production stubs.</p><p>The following example works for tests that use the development version of the stubs:</p><div class="language-java vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">@</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">AutoConfigureStubRunner</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ids</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;com.example:http-server-dsl:+:stubs:8080&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">})</span></span></code></pre></div><p>The following example works for tests that use the production version of stubs:</p><div class="language-java vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">@</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">AutoConfigureStubRunner</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ids</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;com.example:http-server-dsl:+:prod-stubs:8080&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">})</span></span></code></pre></div><p>You can also pass those values in properties from your deployment pipeline.</p>',25)])])}const k=e(n,[["render",o]]);export{c as __pageData,k as default};
